// Define a generic math calculator class MathCalculator<T>.
// The class should support addition, subtraction, multiplication, and division.
class MathCalculator<T> {
	constructor() {}
	private isNumber(type: T): type is number {
		return typeof type === 'number';
	}
	add(a: T, b: T): T {
		if (this.isNumber(a) && this.isNumber(b)) {
			return a + b;
		} else {
			throw new Error('Cannot perform operation on non-numeric type.');
		}
	}
	subtract(a: T, b: T): T {
		if (this.isNumber(a) && this.isNumber(b)) {
			return a - b;
		} else {
			throw new Error('Cannot perform operation on non-numeric type.');
		}
	}
	multiply(a: T, b: T): T {
		if (this.isNumber(a) && this.isNumber(b)) {
			return a * b;
		} else {
			throw new Error('Cannot perform operation on non-numeric type.');
		}
	}

divide(a: T, b: T): T {
		if (this.isNumber(a) && this.isNumber(b)) {
			if (b === 0) {
				throw new Error('Cannot divide by zero.');
			}
			return a / b;
		} else {
			throw new Error('Cannot perform operation on non-numeric type.');
		}
	}
}

